@Test public void testNormalizesMultipleConsecutiveInvisibles() {
    String escaped = "word&#x200b;&#x200c;&#x200d;&shy;break";
    String decoded = "word\u200B\u200C\u200D\u00ADbreak";
    Document doc = Jsoup.parse("<p>" + escaped + "</p>");
    Element p = doc.select("p").first();
    assertEquals("word break", p.text());
    assertEquals(decoded, p.textNodes().get(0).getWholeText());
}

@Test public void testNormalizesInvisiblesAtBoundaries() {
    String escaped = "&shy;start&#x200b;middle&#x200c;end&shy;";
    String decoded = "\u00ADstart\u200Bmiddle\u200Cend\u00AD";
    Document doc = Jsoup.parse("<p>" + escaped + "</p>");
    Element p = doc.select("p").first();
    assertEquals("start middle end", p.text());
    assertEquals(decoded, p.textNodes().get(0).getWholeText());
}

@Test public void testNormalizesInvisiblesWithWhitespace() {
    String escaped = "word1 &shy; &#x200b; word2";
    String decoded = "word1 \u00AD \u200B word2";
    Document doc = Jsoup.parse("<p>" + escaped + "</p>");
    Element p = doc.select("p").first();
    assertEquals("word1 word2", p.text());
    assertEquals(decoded, p.textNodes().get(0).getWholeText());
}
